@app.route('/execute', methods=['POST'])
def execute_generic():
    req_data = request.json
    
    script_code = req_data.get('script')
    index_name = req_data.get('index', '_all')
    agg_type = req_data.get('agg_type', 'terms')
    field = req_data.get('field')
    
    agg_body = {}
    
    if field:
        agg_body = {
            agg_type: {
                "field": field,
                "script": {
                    "inline": script_code,
                    "lang": "painless"
                }
            }
        }
    else:
        agg_body = {
            agg_type: {
                "script": {
                    "inline": script_code,
                    "lang": "painless"
                }
            }
        }
    
    query = {
        "size": 0,
        "aggs": {
            "result": agg_body
        }
    }
    
    result = es.search(index=index_name, body=query)
    return jsonify(result)

@app.route('/update_by_script', methods=['POST'])
def update_by_script():
    req_data = request.json
    
    script_code = req_data.get('script')
    index_name = req_data.get('index')
    doc_id = req_data.get('id')
    params = req_data.get('params', {})
    
    body = {
        "script": {
            "inline": script_code,
            "lang": "painless",
            "params": params
        }
    }
    
    result = es.update(index=index_name, id=doc_id, body=body)
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)